import React, { useState, useEffect, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

function App() {
  // --- PERSISTENCIA DE SESIÓN ---
  const [token, setToken] = useState(localStorage.getItem('nitroToken') || '');
  const [isLoggedIn, setIsLoggedIn] = useState(!!localStorage.getItem('nitroToken'));
  const [userRole, setUserRole] = useState(localStorage.getItem('nitroRole') || '');
  const [usuario, setUsuario] = useState(localStorage.getItem('nitroUser') || '');

  const [authMode, setAuthMode] = useState('login');
  const [form, setForm] = useState({ u: '', p: '', e: '', t: '', code: '' });
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');

  // AXIOS CONFIG: MANDA EL TOKEN EN CADA CLIC
  const api = axios.create({
    baseURL: 'http://localhost:5000/api',
    headers: { Authorization: `Bearer ${token}` }
  });

  const cargarDatos = useCallback(async () => {
    if (!isLoggedIn) return;
    try {
      const [resS, resP] = await Promise.all([api.get('/stats'), api.get('/productos')]);
      setStats(resS.data);
      setProductos(resP.data);
    } catch (e) { if (e.response?.status === 401) handleLogout(); }
  }, [isLoggedIn, token]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario: form.u, clave: form.p });
      localStorage.setItem('nitroToken', res.data.token);
      localStorage.setItem('nitroRole', res.data.rol);
      localStorage.setItem('nitroUser', res.data.user);
      setToken(res.data.token);
      setUserRole(res.data.rol);
      setUsuario(res.data.user);
      setIsLoggedIn(true);
    } catch (e) { alert("Acceso denegado"); }
  };

  const handleLogout = () => {
    localStorage.clear();
    setToken('');
    setIsLoggedIn(false);
    setAuthMode('login');
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4">
        <div className="bg-[#2d333b] p-8 md:p-10 rounded-[40px] shadow-2xl w-full max-w-sm text-white text-center">
          <h2 className="text-3xl font-black mb-6 uppercase tracking-tighter">Mi Tiendita Pro</h2>

          <div className="space-y-3">
            <input className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Usuario" onChange={e => setForm({...form, u: e.target.value})} />

            {authMode === 'register' && (
              <>
                <input className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Gmail real" onChange={e => setForm({...form, e: e.target.value})} />
                <select className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" onChange={e => setNuevoRol(e.target.value)}>
                  <option value="vendedor">Vendedor (Libre)</option>
                  <option value="admin">Administrador (Requiere Código)</option>
                </select>
                {nuevoRol === 'admin' && (
                  <input className="w-full bg-red-900/20 p-4 rounded-2xl border border-red-500 outline-none" placeholder="CÓDIGO ADMIN" onChange={e => setForm({...form, code: e.target.value})} />
                )}
              </>
            )}

            <input type="password" title="pass" className="w-full bg-[#444c56] p-4 rounded-2xl outline-none" placeholder="Contraseña" onChange={e => setForm({...form, p: e.target.value})} />

            <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-3xl text-lg uppercase transition active:scale-95 shadow-lg" 
              onClick={authMode === 'login' ? handleLogin : () => axios.post('http://localhost:5000/api/register', {usuario: form.u, email: form.e, clave: form.p, rol: nuevoRol, adminPass: form.code}).then(()=>setAuthMode('login'))}>
              {authMode.toUpperCase()}
            </button>
            <p className="text-[10px] text-gray-400 font-bold uppercase cursor-pointer" onClick={() => setAuthMode(authMode==='login'?'register':'login')}>
              {authMode === 'login' ? 'Crear Cuenta' : 'Ya tengo cuenta'}
            </p>
          </div>
        </div>
      </div>
    );
  }

  const prodFiltrados = productos.filter(p => p.nombre.toLowerCase().includes(busqueda.toLowerCase()));

  return (
    <div className="min-h-screen bg-gray-50 text-slate-800">
      <Navbar setView={setView} userRole={userRole} logout={handleLogout} busqueda={busqueda} handleBusquedaChange={e => setBusqueda(e.target.value)} />
      <main className="max-w-7xl mx-auto p-4 md:p-12">
        {view === "dashboard" && busqueda === "" ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-in fade-in duration-500">
            <div onClick={() => setView('inv')} className="bg-white p-10 border rounded-[50px] shadow-xl text-center cursor-pointer hover:scale-105 transition">
              <p className="text-xs text-gray-400 font-black uppercase mb-2 italic">Stock</p>
              <p className="text-7xl font-black text-[#1e293b]">{stats.total_productos}</p>
            </div>
            <div className="bg-white p-10 border rounded-[50px] shadow-xl text-center">
              <p className="text-xs text-red-400 font-black uppercase mb-2 italic">Bajo</p>
              <p className="text-7xl font-black text-red-500">{stats.bajo_stock}</p>
            </div>
            <div className="bg-white p-10 border rounded-[50px] shadow-xl text-center">
              <p className="text-xs text-green-400 font-black uppercase mb-2 italic">Dinero</p>
              <p className="text-4xl md:text-5xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <h2 className="text-2xl font-black uppercase tracking-tighter italic">
              {busqueda ? `Resultados: ${busqueda}` : "Inventario"}
            </h2>
            {/* GRID MÓVIL: 2 columnas en cel (grid-cols-2), 4 en compu (md:grid-cols-4) */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 md:gap-8">
              {prodFiltrados.map(p => (
                <div key={p.id} className="bg-white p-4 md:p-6 rounded-[30px] md:rounded-[40px] shadow-xl border border-gray-100 text-center relative group">
                  <img src={p.imagen ? `http://localhost:5000/uploads/${p.imagen}` : 'https://via.placeholder.com/150'} className="w-full h-32 md:h-40 object-cover rounded-3xl mb-4 shadow-sm" alt="p" />
                  <h3 className="font-black uppercase text-[10px] md:text-sm mb-1 line-clamp-1">{p.nombre}</h3>
                  <p className="text-green-600 font-black text-xl md:text-2xl">${p.precio_venta}</p>
                  {userRole === 'admin' && <button onClick={() => api.delete(`/productos/${p.id}`).then(()=>cargarDatos())} className="absolute top-2 right-2 text-red-300 hover:text-red-600"><i className="fas fa-trash"></i></button>}
                </div>
              ))}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
